+        for code in MissionFailureCode::all() {
+            assert!(!code.human_hint().trim().is_empty());
+            assert!(!code.machine_hint().trim().is_empty());
+            assert!(!code.reason_code().trim().is_empty());
+            assert!(!code.error_code().trim().is_empty());
+        }
